#include <bits/stdc++.h>
using namespace std;

const int N = 200 + 5;
long long dp[N], Prime[55];
int cur = 0;

bool is_Prime(int x)
{
    if(x < 2) return 0;
    for(int i = 2; i * i <= x; i++)
        if(x % i == 0) return 0;
    return 1;
}

void Get_Prime()
{
    for(int i = 2; i <= 200; i++)
        if(is_Prime(i)) Prime[++cur] = i;
}

int main()
{
    Get_Prime();
    int n;
    while(cin >> n)
    {
        memset(dp, 0, sizeof dp);
        dp[0] = 1;
        for(int i = 1; i <= cur; i++)
            for(int j = Prime[i]; j <= n; j++)
                dp[j] += dp[j - Prime[i]];
        cout << dp[n] << endl;
    }
}
